package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private File tempFile;

    @BeforeEach
    void setUp() throws IOException {
        tempFile = File.createTempFile("csvformattest", ".csv");
        tempFile.deleteOnExit();
    }

    @AfterEach
    void tearDown() {
        if (tempFile != null && tempFile.exists()) {
            tempFile.delete();
        }
    }

    @Test
    void testPrintCreatesCSVPrinter() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVPrinter printer = format.print(tempFile.toPath(), StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrintWithDifferentCharset() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVPrinter printer = format.print(tempFile.toPath(), StandardCharsets.US_ASCII);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrintThrowsIOExceptionForInvalidFile() {
        CSVFormat format = CSVFormat.DEFAULT;
        File invalidFile = new File("/invalid_path/invalid_file.csv");
        assertThrows(IOException.class, () -> format.print(invalidFile.toPath(), StandardCharsets.UTF_8));
    }

}
